interface EditOfferPageProps {
  params: Promise<{ id: string }>
}

export default async function EditOfferPage({ params }: EditOfferPageProps): JSX.Element {
  const resolvedParams = await params
  const offer = await getOffer(resolvedParams.id)
  if (!offer) {
    notFound()
  }

  const partners = await getPartners()

  // Format dates for the input[type=date] if they exist
  const formattedOffer = {
    ...offer,
    startDate: offer.startDate ? new Date(offer.startDate).toISOString().split('T')[0] : "",
    endDate: offer.endDate ? new Date(offer.endDate).toISOString().split('T')[0] : "",
  }

  return (
    <div className="flex-1 space-y-4 p-8 pt-6">
      <div className="flex items-center justify-between space-y-2">
        <h2 className="text-3xl font-bold tracking-tight">Edit Offer</h2>
      </div>
      <OfferForm initialData={formattedOffer} partners={partners} />
    </div>
  )
}

"use client"

import { Badge } from "@hu-partner/ui"
import { type ColumnDef } from "@tanstack/react-table"

import { OfferCellAction } from "./cell-action"

export type OfferColumn = {
  id: string
  title: string
  code: string | null
  discountType: string
  discountValue: number
  status: "DRAFT" | "REVIEW" | "PUBLISHED" | "ARCHIVED"
  partner: {
    name: string
  }
}

export const columns: ColumnDef<OfferColumn>[] = [
  {
    accessorKey: "title",
    header: "Offer",
  },
  {
    accessorKey: "partner.name",
    header: "Partner",
  },
  {
    accessorKey: "code",
    header: "Code",
    cell: ({ row }): void => row.getValue("code") || "-"
  },
  {
    accessorKey: "discountValue",
    header: "Value",
    cell: ({ row }): unknown => {
      const type = row.getValue("discountType")
      const val = row.getValue("discountValue")
      if (type === "PERCENTAGE") return `${val}%`
      if (type === "FIXED") return `$${val}`
      return val
    }
  },
  {
    accessorKey: "status",
    header: "Status",
    cell: ({ row }): JSX.Element => {
      const status = row.getValue("status")
      const variant = status === "PUBLISHED" ? "default" : status === "DRAFT" ? "secondary" : "destructive"
      return <Badge variant={variant}>{status}</Badge>
    },
  },
  {
    id: "actions",
    cell: ({ row }): JSX.Element => <OfferCellAction data={row.original} />
  },
]

